/* Internal: does the pair (u_i, u_j) agree on its registered overlap?
 * Returns 1u8 iff an intersection is registered AND both sections exist AND
 * both restrict cleanly to the intersection AND the restrictions are byte
 * equal.  A missing intersection returns 0u8 (refusal -- the correctness fix
 * over the gospel candidate's silent skip).  presheaf id at cover[0..31].
 * ri/rj point to module-scope BSS globals SH_R_I/SH_R_J -- never null;
 * the vacuous null-check (deferred audit F-SH-null) is removed here. */
fn sh_pair_agrees(cover: *u8, u_i: u32, u_j: u32) -> u8 {
    let int_slot : u32 = sh_find_intersection(u_i, u_j)
    if int_slot == SHEAF_SENT { return 0u8 }
    let inter : u32 = SH_INT_INTER[int_slot]
    let pre_p : *u8 = cover
    let sec_i : u32 = sh_find_section(pre_p, u_i)
    if sec_i == SHEAF_SENT { return 0u8 }
    let sec_j : u32 = sh_find_section(pre_p, u_j)
    if sec_j == SHEAF_SENT { return 0u8 }
    let ri : *u8 = (&SH_R_I as u64) as *u8
    let rj : *u8 = (&SH_R_J as u64) as *u8
    let rc_i : i32 = sh_restrict(sec_i, u_i, inter, ri)
    if rc_i != SHEAF_OK { return 0u8 }
    let rc_j : i32 = sh_restrict(sec_j, u_j, inter, rj)
    if rc_j != SHEAF_OK { return 0u8 }
    if ident_eq(ri, rj) == 0u8 { return 0u8 }
    return 1u8
}

